const _count = function count() {
  return function count(diagram) {
    const rows = diagram.length;
    if (rows === 0) return 0;
    const cols = diagram[0].length;
    if (cols === 0) return 0;

    // Collect all '+' corner positions
    const corners = [];
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        if (diagram[r][c] === '+') corners.push([r, c]);
      }
    }

    let rects = 0;
    // For each pair of corners as top-left (i) and bottom-right (j)
    for (let i = 0; i < corners.length; i++) {
      for (let j = i + 1; j < corners.length; j++) {
        const [r1, c1] = corners[i];
        const [r2, c2] = corners[j];
        if (r1 >= r2 || c1 >= c2) continue;
        // Other two corners must be '+'
        if (diagram[r1][c2] !== '+' || diagram[r2][c1] !== '+') continue;

        // Check top edge: row r1, cols c1+1..c2-1 must be '-' or '+'
        let ok = true;
        for (let c = c1 + 1; c < c2; c++) {
          const ch = diagram[r1][c];
          if (ch !== '-' && ch !== '+') { ok = false; break; }
        }
        if (!ok) continue;

        // Check bottom edge: row r2, cols c1+1..c2-1
        for (let c = c1 + 1; c < c2; c++) {
          const ch = diagram[r2][c];
          if (ch !== '-' && ch !== '+') { ok = false; break; }
        }
        if (!ok) continue;

        // Check left edge: col c1, rows r1+1..r2-1 must be '|' or '+'
        for (let r = r1 + 1; r < r2; r++) {
          const ch = diagram[r][c1];
          if (ch !== '|' && ch !== '+') { ok = false; break; }
        }
        if (!ok) continue;

        // Check right edge: col c2, rows r1+1..r2-1
        for (let r = r1 + 1; r < r2; r++) {
          const ch = diagram[r][c2];
          if (ch !== '|' && ch !== '+') { ok = false; break; }
        }
        if (!ok) continue;

        rects++;
      }
    }
    return rects;
  };
};

